import { describe, expect, test } from 'vitest'

import { indent, lines, lowerFirst, pluralize, upperFirst } from '../template'

describe('lowerFirst', () => {
  test('lowercases the first character', () => {
    expect(lowerFirst('User')).toBe('user')
    expect(lowerFirst('ABC')).toBe('aBC')
  })

  test('handles single character', () => {
    expect(lowerFirst('A')).toBe('a')
  })

  test('handles already lowercase', () => {
    expect(lowerFirst('user')).toBe('user')
  })
})

describe('upperFirst', () => {
  test('uppercases the first character', () => {
    expect(upperFirst('user')).toBe('User')
    expect(upperFirst('abc')).toBe('Abc')
  })

  test('handles already uppercase', () => {
    expect(upperFirst('User')).toBe('User')
  })
})

describe('pluralize', () => {
  test('adds s to regular words', () => {
    expect(pluralize('User')).toBe('Users')
    expect(pluralize('Post')).toBe('Posts')
  })

  test('handles words ending in consonant + y', () => {
    expect(pluralize('Category')).toBe('Categories')
    expect(pluralize('Entry')).toBe('Entries')
  })

  test('preserves words ending in vowel + y', () => {
    expect(pluralize('Key')).toBe('Keys')
    expect(pluralize('Day')).toBe('Days')
    expect(pluralize('Boy')).toBe('Boys')
    expect(pluralize('Guy')).toBe('Guys')
  })

  test('does not double-pluralize words ending in s', () => {
    expect(pluralize('address')).toBe('address')
    expect(pluralize('Users')).toBe('Users')
  })
})

describe('lines', () => {
  test('joins non-empty strings with newlines', () => {
    expect(lines('a', 'b', 'c')).toBe('a\nb\nc')
  })

  test('filters out empty strings', () => {
    expect(lines('a', '', 'b')).toBe('a\nb')
  })
})

describe('indent', () => {
  test('indents lines by specified number of spaces', () => {
    expect(indent('a\nb', 4)).toBe('    a\n    b')
  })

  test('defaults to 2 spaces', () => {
    expect(indent('a\nb')).toBe('  a\n  b')
  })

  test('preserves empty lines without trailing whitespace', () => {
    expect(indent('a\n\nb', 2)).toBe('  a\n\n  b')
  })
})

