import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import { onGenerate } from '../on-generate'

describe('onGenerate', () => {
  let tmpDir: string

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'rest-gen-test-'))
  })

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true })
  })

  test('writes rest-client.ts to the output directory', async () => {
    const options = {
      generator: {
        output: { value: tmpDir, fromEnvVar: null },
        config: {},
        name: 'restClient',
        provider: { value: 'prisma-generator-rest-client', fromEnvVar: null },
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '',
      },
      dmmf: {
        datamodel: {
          models: [
            {
              name: 'Post',
              dbName: null,
              schema: null,
              fields: [
                {
                  kind: 'scalar',
                  name: 'id',
                  type: 'Int',
                  isRequired: true,
                  isList: false,
                  isUnique: false,
                  isId: true,
                  isReadOnly: false,
                  hasDefaultValue: true,
                },
                {
                  kind: 'scalar',
                  name: 'title',
                  type: 'String',
                  isRequired: true,
                  isList: false,
                  isUnique: false,
                  isId: false,
                  isReadOnly: false,
                  hasDefaultValue: false,
                },
              ],
              uniqueFields: [],
              uniqueIndexes: [],
              primaryKey: null,
            },
          ],
          enums: [],
          types: [],
          indexes: [],
        },
        schema: {
          enumTypes: { prisma: [] },
          inputObjectTypes: {},
          outputObjectTypes: { model: [], prisma: [] },
          fieldRefTypes: {},
        },
        mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
      },
      datasources: [],
      datamodel: '',
      schemaPath: '',
      version: 'test',
      otherGenerators: [],
    } as unknown as GeneratorOptions

    await onGenerate(options)

    const outputPath = path.join(tmpDir, 'rest-client.ts')
    expect(fs.existsSync(outputPath)).toBe(true)

    const content = fs.readFileSync(outputPath, 'utf-8')
    expect(content).toContain('export interface Post {')
    expect(content).toContain('postFindMany')
    expect(content).toContain('postCreate')
  })

  test('creates the output directory if it does not exist', async () => {
    const nestedDir = path.join(tmpDir, 'nested', 'output')

    const options = {
      generator: {
        output: { value: nestedDir, fromEnvVar: null },
        config: {},
        name: 'restClient',
        provider: { value: 'prisma-generator-rest-client', fromEnvVar: null },
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '',
      },
      dmmf: {
        datamodel: {
          models: [],
          enums: [],
          types: [],
          indexes: [],
        },
        schema: {
          enumTypes: { prisma: [] },
          inputObjectTypes: {},
          outputObjectTypes: { model: [], prisma: [] },
          fieldRefTypes: {},
        },
        mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
      },
      datasources: [],
      datamodel: '',
      schemaPath: '',
      version: 'test',
      otherGenerators: [],
    } as unknown as GeneratorOptions

    await onGenerate(options)

    expect(fs.existsSync(path.join(nestedDir, 'rest-client.ts'))).toBe(true)
  })

  test('throws when no output directory is specified', async () => {
    const options = {
      generator: {
        output: null,
        config: {},
        name: 'restClient',
        provider: { value: 'prisma-generator-rest-client', fromEnvVar: null },
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '',
      },
      dmmf: {
        datamodel: { models: [], enums: [], types: [], indexes: [] },
        schema: {
          enumTypes: { prisma: [] },
          inputObjectTypes: {},
          outputObjectTypes: { model: [], prisma: [] },
          fieldRefTypes: {},
        },
        mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
      },
      datasources: [],
      datamodel: '',
      schemaPath: '',
      version: 'test',
      otherGenerators: [],
    } as unknown as GeneratorOptions

    await expect(onGenerate(options)).rejects.toThrow('No output directory specified')
  })
})

